using System;
using System.Diagnostics;

public class PdfGenerator
{
    public bool GeneratePdf(string htmlFilePath, string pdfPath, PageSize pageSize = PageSize.A4, Orientation orientation = Orientation.Portrait)
    {
        try
        {
            var wkhtmltopdfPath = @"C:\path\to\wkhtmltopdf.exe"; // replace with your path

            var processInfo = new ProcessStartInfo(wkhtmltopdfPath);
            processInfo.Arguments = $"--page-size {pageSize} --orientation {orientation} {htmlFilePath} {pdfPath}";
            processInfo.UseShellExecute = false;
            processInfo.RedirectStandardError = true;

            using (var process = Process.Start(processInfo))
            {
                process.WaitForExit();

                if (process.ExitCode != 0)
                {
                    Console.WriteLine($"Error generating PDF: Exit code {process.ExitCode}");
                    return false;
                }
            }

            return true;
        }
        catch (Exception ex)
        {
            Console.WriteLine($"An error occurred: {ex.Message}");
            return false;
        }
    }
}

public enum PageSize
{
    A4,
    Letter,
    Legal
}

public enum Orientation
{
    Portrait,
    Landscape
}